mapper.select:
select
	t1.id                             ,
	t1.secret_level                   ,
	t1.project_id                     ,
	t1.project_name                   ,
	t1.task_id                        ,
	t1.task_name                      ,
	t1.sub_project_id                 ,
	t1.sub_project_code               ,
	t1.sub_project_name               ,
	t1.pf_gg                          ,
	t1.pf_xg                          ,
	t1.pf_xnzb                        ,
	t1.pf_type                        ,
	t1.pf_num                         ,
	t1.ys_gg                          ,
	t1.ys_xnzb                        ,
	t1.ys_xg                          ,
	t1.ys_zzcs                        ,
	t1.ys_ccrq_date                   ,
	t1.ys_ccbh                        ,
	t1.ys_zys_date                    ,
	t1.ys_dh_date                     ,
	t1.ys_user                        ,
	t1.ys_dept                        ,
	t1.ys_ysjl                        ,
	t1.ys_idea                        ,
	t1.hpj_date                       ,
	t1.hpj_dept                       ,
	t1.hpj_user                       ,
	t1.hpj_yyxg                       ,
	t1.hpj_sxjz                       ,
	t1.hpj_czwt                       ,
	t1.created_by                     ,
	t1.creation_date                  ,
	t1.last_updated_by                ,
	t1.last_update_date               ,
	t1.last_update_ip                 ,
	t1.version                        ,
	t1.created_dept                   ,
	t1.org_identity                   ,
	t1.attribute_01                   ,
	t1.attribute_02                   ,
	t1.attribute_03                   ,
	t1.attribute_04                   ,
	t1.attribute_05                   ,
	t1.attribute_06                   ,
	t1.attribute_07                   ,
	t1.attribute_08                   ,
	t1.attribute_09                   ,
	t1.attribute_10                   
from pm_project_ys_hpj 	t1


			and t1.ID =#{id}


			and t1.SECRET_LEVEL =#{secretLevel}


			and t1.PROJECT_ID =#{projectId}


			and t1.PROJECT_NAME =#{projectName}


			and t1.TASK_ID =#{taskId}


			and t1.TASK_NAME =#{taskName}


			and t1.SUB_PROJECT_ID =#{subProjectId}


			and t1.SUB_PROJECT_CODE =#{subProjectCode}


			and t1.SUB_PROJECT_NAME =#{subProjectName}


			and t1.PF_GG =#{pfGg}


			and t1.PF_XG =#{pfXg}


			and t1.PF_XNZB =#{pfXnzb}


			and t1.PF_TYPE =#{pfType}


			and t1.PF_NUM =#{pfNum}


			and t1.YS_GG =#{ysGg}


			and t1.YS_XNZB =#{ysXnzb}


			and t1.YS_XG =#{ysXg}


			and t1.YS_ZZCS =#{ysZzcs}


			and t1.YS_CCRQ_DATE >= #{ysCcrqDateBegin}


			and t1.YS_CCRQ_DATE <= #{ysCcrqDateEnd}


			and t1.YS_CCBH =#{ysCcbh}


			and t1.YS_ZYS_DATE >= #{ysZysDateBegin}


			and t1.YS_ZYS_DATE <= #{ysZysDateEnd}


			and t1.YS_DH_DATE >= #{ysDhDateBegin}


			and t1.YS_DH_DATE <= #{ysDhDateEnd}


			and t1.YS_USER =#{ysUser}


			and t1.YS_DEPT =#{ysDept}


			and t1.YS_YSJL =#{ysYsjl}


			and t1.YS_IDEA =#{ysIdea}


			and t1.HPJ_DATE >= #{hpjDateBegin}


			and t1.HPJ_DATE <= #{hpjDateEnd}


			and t1.HPJ_DEPT =#{hpjDept}


			and t1.HPJ_USER =#{hpjUser}


			and t1.HPJ_YYXG =#{hpjYyxg}


			and t1.HPJ_SXJZ =#{hpjSxjz}


			and t1.HPJ_CZWT =#{hpjCzwt}


			and t1.CREATED_BY =#{createdBy}


			and t1.CREATION_DATE =#{creationDate}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.VERSION =#{version}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.ATTRIBUTE_01 =#{attribute01}


			and t1.ATTRIBUTE_02 =#{attribute02}


			and t1.ATTRIBUTE_03 =#{attribute03}


			and t1.ATTRIBUTE_04 =#{attribute04}


			and t1.ATTRIBUTE_05 =#{attribute05}


			and t1.ATTRIBUTE_06 =#{attribute06}


			and t1.ATTRIBUTE_07 =#{attribute07}


			and t1.ATTRIBUTE_08 =#{attribute08}


			and t1.ATTRIBUTE_09 =#{attribute09}


			and t1.ATTRIBUTE_10 =#{attribute10}
